'use client'

import { UserProfile as WorkOSUserProfile } from '@workos-inc/widgets'
import type { BaseWidgetProps } from '../types/auth'

/**
 * User Profile Widget
 *
 * Displays and allows editing of user profile information:
 * - Profile picture
 * - Name and email
 * - Connected accounts (OAuth providers)
 *
 * @example
 * ```tsx
 * // With AuthKit (recommended)
 * import { useAuth } from '@mdxui/auth'
 * import { UserProfile } from '@mdxui/auth/widgets'
 *
 * function ProfilePage() {
 *   const { getAccessToken } = useAuth()
 *   return <UserProfile authToken={getAccessToken} />
 * }
 * ```
 *
 * @example
 * ```tsx
 * // With string token
 * <UserProfile authToken={myToken} />
 * ```
 */
export function UserProfile({ authToken, className }: BaseWidgetProps) {
  return (
    <div className={className}>
      <WorkOSUserProfile authToken={authToken} />
    </div>
  )
}
