'use client'

import { WorkOsWidgets } from '@workos-inc/widgets'
import { useEffect, useState } from 'react'
import type { WidgetsProviderProps } from '../types/auth'

/**
 * Hook to detect dark mode from document class or system preference
 *
 * @returns Object with isDark state and mounted flag
 *
 * @example
 * ```tsx
 * const { isDark, mounted } = useThemeDetection()
 * const appearance = mounted ? (isDark ? 'dark' : 'light') : 'inherit'
 * ```
 */
export function useThemeDetection() {
  const [mounted, setMounted] = useState(false)
  const [isDark, setIsDark] = useState(false)

  useEffect(() => {
    setMounted(true)

    const checkDarkMode = () => {
      const isDarkClass = document.documentElement.classList.contains('dark')
      const prefersDark = window.matchMedia(
        '(prefers-color-scheme: dark)'
      ).matches
      setIsDark(
        isDarkClass ||
          (!document.documentElement.classList.contains('light') && prefersDark)
      )
    }

    checkDarkMode()

    // Watch for class changes on html element
    const observer = new MutationObserver(checkDarkMode)
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['class'],
    })

    // Watch for system preference changes
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
    mediaQuery.addEventListener('change', checkDarkMode)

    return () => {
      observer.disconnect()
      mediaQuery.removeEventListener('change', checkDarkMode)
    }
  }, [])

  return { isDark, mounted }
}

/**
 * Provider for WorkOS widgets with automatic theme detection
 *
 * Wraps children with WorkOsWidgets context and automatically detects
 * light/dark mode from document classes or system preference.
 *
 * @example
 * ```tsx
 * import { WidgetsProvider } from '@mdxui/auth'
 * import { UserProfile } from '@mdxui/auth/widgets'
 *
 * function App() {
 *   return (
 *     <WidgetsProvider>
 *       <UserProfile authToken={getAccessToken} />
 *     </WidgetsProvider>
 *   )
 * }
 * ```
 *
 * @example
 * ```tsx
 * // With explicit theme
 * <WidgetsProvider appearance="dark" radius="large">
 *   <UserProfile authToken={token} />
 * </WidgetsProvider>
 * ```
 */
export function WidgetsProvider({
  children,
  appearance,
  radius = 'medium',
  scaling = '100%',
}: WidgetsProviderProps) {
  const { isDark, mounted } = useThemeDetection()

  // Use provided appearance, or auto-detect from theme
  // Use "inherit" until mounted to avoid hydration mismatch
  const resolvedAppearance =
    appearance ?? (mounted ? (isDark ? 'dark' : 'light') : 'inherit')

  // Note: Widgets always use api.workos.com - custom Authentication API domains
  // do NOT support widget endpoints. Only authentication uses custom domains.
  return (
    <WorkOsWidgets
      theme={{
        appearance: resolvedAppearance,
        radius,
        scaling,
      }}
      elements={{
        primaryButton: {
          variant: 'solid',
        },
        secondaryButton: {
          variant: 'outline',
        },
      }}
    >
      {children}
    </WorkOsWidgets>
  )
}
