/**
 * Runtime configuration for the prebuilt AuthApp
 * Loaded from /auth-config.json at startup
 */

/** Supported OAuth provider identifiers */
export type OAuthProvider = 'github' | 'google' | 'microsoft' | 'apple'

/** Maps friendly names to WorkOS provider IDs */
export const PROVIDER_MAP: Record<OAuthProvider, string> = {
  github: 'GitHubOAuth',
  google: 'GoogleOAuth',
  microsoft: 'MicrosoftOAuth',
  apple: 'AppleOAuth',
}

/** Display metadata for OAuth providers */
export const PROVIDER_META: Record<OAuthProvider, { name: string; color: string }> = {
  github: { name: 'GitHub', color: '#24292f' },
  google: { name: 'Google', color: '#4285f4' },
  microsoft: { name: 'Microsoft', color: '#00a4ef' },
  apple: { name: 'Apple', color: '#000000' },
}

export interface AuthAppRuntimeConfig {
  /** WorkOS client ID (required) */
  clientId: string
  /** OAuth redirect URI (optional) */
  redirectUri?: string
  /** WorkOS API hostname (optional) */
  apiHostname?: string
  /** Enable dev mode (optional) */
  devMode?: boolean
  /** App name displayed in UI */
  appName?: string
  /** App tagline (optional) */
  tagline?: string
  /** Logo URL (optional) */
  logoUrl?: string
  /** Behavior when user is not authenticated: 'signIn' auto-triggers auth, 'landing' shows welcome page */
  onUnauthenticated?: 'landing' | 'redirect' | 'allow' | 'signIn'
  /** OAuth providers to show on landing page (e.g. ['github', 'google']) */
  providers?: OAuthProvider[]
  /** Base URL for login redirects (defaults to current origin) */
  loginUrl?: string
}

export class ConfigError extends Error {
  constructor(
    message: string,
    public readonly cause?: unknown
  ) {
    super(message)
    this.name = 'ConfigError'
  }
}

/**
 * Fetches runtime configuration from /auth-config.json
 */
export async function loadConfig(): Promise<AuthAppRuntimeConfig> {
  try {
    const response = await fetch('/auth-config.json')

    if (!response.ok) {
      if (response.status === 404) {
        throw new ConfigError(
          'Configuration file not found. Please create /auth-config.json with your WorkOS client ID.'
        )
      }
      throw new ConfigError(`Failed to load configuration: ${response.status} ${response.statusText}`)
    }

    const config = await response.json()

    // Validate required fields
    if (!config.clientId) {
      throw new ConfigError('Configuration error: "clientId" is required in auth-config.json')
    }

    return config as AuthAppRuntimeConfig
  } catch (error) {
    if (error instanceof ConfigError) {
      throw error
    }
    throw new ConfigError('Failed to load configuration', error)
  }
}
