'use client'

import { IdProvider } from '@id.org.ai/react'
import type { IdentityProviderProps } from '../types/auth'
import { WidgetsProvider } from './widgets-provider'

/**
 * Identity provider that wraps your app with id.org.ai authentication.
 *
 * This provider sets up authentication context for your application and
 * automatically includes the WidgetsProvider for WorkOS widgets.
 *
 * @example
 * ```tsx
 * import { IdentityProvider } from '@mdxui/auth'
 *
 * function App() {
 *   return (
 *     <IdentityProvider
 *       clientId="client_xxx"
 *       devMode={process.env.NODE_ENV === 'development'}
 *     >
 *       <YourApp />
 *     </IdentityProvider>
 *   )
 * }
 * ```
 *
 * @example
 * ```tsx
 * // With custom redirect URI and returnTo support
 * <IdentityProvider
 *   clientId="client_xxx"
 *   redirectUri="https://app.example.com/dashboard"
 *   onRedirectCallback={({ state }) => {
 *     // Navigate to the page the user was trying to access
 *     if (state?.returnTo) navigate(state.returnTo as string)
 *   }}
 * >
 *   <YourApp />
 * </IdentityProvider>
 * ```
 */
export function IdentityProvider({
  clientId,
  apiHostname,
  devMode: _devMode,
  redirectUri,
  onRedirectCallback,
  children,
}: IdentityProviderProps) {
  // Build redirect URI - defaults to current origin (no trailing slash)
  // Note: WorkOS AuthKit internally appends a trailing slash, so register
  // "https://yourdomain.com/" (with slash) in WorkOS dashboard
  const resolvedRedirectUri =
    redirectUri ??
    (typeof window !== 'undefined' ? window.location.origin : undefined)

  // Default redirect callback - navigate to returnTo path or clean URL params
  const handleRedirectCallback =
    onRedirectCallback ??
    (({ state }: { state: Record<string, unknown> | null }) => {
      if (typeof window !== 'undefined') {
        // Navigate to returnTo path if provided via signIn({ state: { returnTo } })
        const returnTo = state?.returnTo
        if (typeof returnTo === 'string' && returnTo.startsWith('/')) {
          window.history.replaceState({}, '', returnTo)
          return
        }
        // Otherwise just clean the URL (remove code/state params)
        const url = new URL(window.location.href)
        url.searchParams.delete('code')
        url.searchParams.delete('state')
        window.history.replaceState({}, '', url.pathname)
      }
    })

  return (
    <IdProvider
      clientId={clientId}
      baseUrl={apiHostname ?? 'https://id.org.ai'}
      redirectUri={resolvedRedirectUri}
      onRedirectCallback={({ user: _user, state }) => {
        handleRedirectCallback({ state: state ?? null })
      }}
    >
      <WidgetsProvider>{children}</WidgetsProvider>
    </IdProvider>
  )
}

/**
 * Minimal identity provider without WidgetsProvider
 *
 * Use this if you want to set up widgets separately or don't need them.
 *
 * @example
 * ```tsx
 * import { IdentityProviderMinimal, WidgetsProvider } from '@mdxui/auth'
 *
 * function App() {
 *   return (
 *     <IdentityProviderMinimal clientId="client_xxx">
 *       <WidgetsProvider appearance="dark">
 *         <YourApp />
 *       </WidgetsProvider>
 *     </IdentityProviderMinimal>
 *   )
 * }
 * ```
 */
