/**
 * Route Presets
 *
 * Default route configurations for AuthApp. These provide a zero-config
 * experience - just provide branding and identity config to get started.
 */

import { Key, Monitor, Plug, Shield, User, Users } from "lucide-react";
import {
	ApiKeysPage,
	IntegrationsPage,
	ProfilePage,
	SecurityPage,
	SessionsPage,
	TeamPage,
} from "./pages";
import type { AuthAppRoute, RouteGroup } from "./types";

/**
 * Default route groups for organizing navigation
 */
export const defaultGroups: RouteGroup[] = [
	{ id: "main", order: 0 },
	{ id: "account", label: "Account", order: 10 },
	{ id: "developer", label: "Developer", order: 20 },
	{ id: "admin", label: "Admin", order: 30 },
];

/**
 * Account management routes
 */
export const accountRoutes: AuthAppRoute[] = [
	{
		key: "profile",
		path: "/profile",
		label: "Profile",
		group: "account",
		icon: User,
		component: ProfilePage,
		enabled: true,
		public: false,
	},
	{
		key: "security",
		path: "/security",
		label: "Security",
		group: "account",
		icon: Shield,
		component: SecurityPage,
		enabled: true,
		public: false,
	},
	{
		key: "sessions",
		path: "/sessions",
		label: "Sessions",
		group: "account",
		icon: Monitor,
		component: SessionsPage,
		enabled: true,
		public: false,
	},
];

/**
 * Developer-focused routes
 */
export const developerRoutes: AuthAppRoute[] = [
	{
		key: "api-keys",
		path: "/api-keys",
		label: "API Keys",
		group: "developer",
		icon: Key,
		component: ApiKeysPage,
		enabled: true,
		public: false,
	},
	{
		key: "integrations",
		path: "/integrations",
		label: "Integrations",
		group: "developer",
		icon: Plug,
		component: IntegrationsPage,
		enabled: true,
		public: false,
	},
];

/**
 * Admin/team management routes
 *
 * These routes require organization context and specific permissions.
 * They are automatically hidden from navigation when requirements aren't met.
 */
export const adminRoutes: AuthAppRoute[] = [
	{
		key: "team",
		path: "/team",
		label: "Team",
		group: "admin",
		icon: Users,
		component: TeamPage,
		enabled: true,
		public: false,
		requiresOrganization: true,
		requiredPermissions: ["widgets:users-table:manage"],
	},
];

/**
 * Default routes - all standard routes combined
 *
 * Includes: account, developer (API keys + integrations), and admin routes
 */
export const defaultRoutes: AuthAppRoute[] = [
	...accountRoutes,
	...developerRoutes,
	...adminRoutes,
];
