'use client'

import { useAuth } from '../../hooks/use-auth'
import { UserSecurity } from '../../widgets/user-security'
import { WidgetErrorBoundary } from '../components'

/**
 * Security page that renders the UserSecurity widget
 *
 * Allows users to manage password and MFA settings.
 */
export function SecurityPage() {
  const { user, getAccessToken, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Security</h1>
          <p className="text-muted-foreground">Manage your password and authentication settings</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to manage your security settings.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">Security</h1>
        <p className="text-muted-foreground">Manage your password and authentication settings</p>
      </div>
      <WidgetErrorBoundary widgetName="security">
        <UserSecurity authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
