'use client'

/**
 * Auth Shell Configuration Context
 *
 * Provides configuration and route information to shell components.
 * Use the hooks to access config, routes, and branding.
 */

import { createContext, useContext, useMemo, type ReactNode } from 'react'
import type { AuthAppConfig, AuthAppRoute, AuthShellBranding, RouteGroup } from './types'
import { defaultGroups, defaultRoutes } from './route-presets'

/**
 * Context value shape
 */
interface AuthShellConfigContextValue {
  /** Full configuration */
  config: AuthAppConfig
  /** All enabled routes */
  routes: AuthAppRoute[]
  /** Routes organized by group */
  routesByGroup: Map<string, AuthAppRoute[]>
  /** Route groups sorted by order */
  groups: RouteGroup[]
  /** Branding configuration */
  branding: AuthShellBranding
  /** Base path for routes */
  basePath: string
}

const AuthShellConfigContext = createContext<AuthShellConfigContextValue | null>(null)

/**
 * Props for AuthShellConfigProvider
 */
interface AuthShellConfigProviderProps {
  /** Shell configuration */
  config: AuthAppConfig
  /** Children to render */
  children: ReactNode
}

/**
 * Provides shell configuration context to children
 *
 * @example
 * ```tsx
 * <AuthShellConfigProvider config={config}>
 *   <AuthShell>
 *     <Outlet />
 *   </AuthShell>
 * </AuthShellConfigProvider>
 * ```
 */
export function AuthShellConfigProvider({ config, children }: AuthShellConfigProviderProps) {
  const value = useMemo<AuthShellConfigContextValue>(() => {
    // Filter to enabled routes only
    const routes = config.routes ?? defaultRoutes
    const enabledRoutes = routes.filter((route) => route.enabled !== false)

    // Sort groups by order
    const groups = [...(config.groups ?? defaultGroups)].sort((a, b) => (a.order ?? 0) - (b.order ?? 0))

    // Organize routes by group
    const routesByGroup = new Map<string, AuthAppRoute[]>()

    // Initialize groups
    for (const group of groups) {
      routesByGroup.set(group.id, [])
    }

    // Sort routes into groups
    for (const route of enabledRoutes) {
      const groupId = route.group ?? 'main'
      const groupRoutes = routesByGroup.get(groupId) ?? []
      groupRoutes.push(route)
      routesByGroup.set(groupId, groupRoutes)
    }

    // Sort routes within each group by order
    for (const [groupId, routes] of routesByGroup) {
      routesByGroup.set(
        groupId,
        routes.sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
      )
    }

    return {
      config,
      routes: enabledRoutes,
      routesByGroup,
      groups,
      branding: config.branding,
      basePath: config.basePath ?? '',
    }
  }, [config])

  return (
    <AuthShellConfigContext.Provider value={value}>
      {children}
    </AuthShellConfigContext.Provider>
  )
}

/**
 * Access the full shell configuration context
 *
 * @throws Error if used outside AuthShellConfigProvider
 *
 * @example
 * ```tsx
 * function MyComponent() {
 *   const { config, routes, branding } = useAuthShellConfig()
 *   return <div>{branding.name}</div>
 * }
 * ```
 */
export function useAuthShellConfig(): AuthShellConfigContextValue {
  const context = useContext(AuthShellConfigContext)
  if (!context) {
    throw new Error('useAuthShellConfig must be used within AuthShellConfigProvider')
  }
  return context
}

/**
 * Access enabled routes array
 *
 * @example
 * ```tsx
 * function RouteList() {
 *   const routes = useAuthShellRoutes()
 *   return routes.map(r => <Link key={r.key} to={r.path}>{r.label}</Link>)
 * }
 * ```
 */
export function useAuthShellRoutes(): AuthAppRoute[] {
  const { routes } = useAuthShellConfig()
  return routes
}

/**
 * Access routes organized by group
 *
 * @example
 * ```tsx
 * function GroupedNav() {
 *   const { routesByGroup, groups } = useAuthShellRoutesByGroup()
 *   return groups.map(g => (
 *     <div key={g.id}>
 *       {g.label && <h3>{g.label}</h3>}
 *       {routesByGroup.get(g.id)?.map(r => <Link to={r.path}>{r.label}</Link>)}
 *     </div>
 *   ))
 * }
 * ```
 */
export function useAuthShellRoutesByGroup(): {
  routesByGroup: Map<string, AuthAppRoute[]>
  groups: RouteGroup[]
} {
  const { routesByGroup, groups } = useAuthShellConfig()
  return { routesByGroup, groups }
}

/**
 * Access branding configuration
 *
 * @example
 * ```tsx
 * function Header() {
 *   const branding = useAuthShellBranding()
 *   return (
 *     <header>
 *       {branding.logo}
 *       <span>{branding.name}</span>
 *     </header>
 *   )
 * }
 * ```
 */
export function useAuthShellBranding(): AuthShellBranding {
  const { branding } = useAuthShellConfig()
  return branding
}

/**
 * Get full path with base path prefix
 *
 * @example
 * ```tsx
 * function NavLink({ route }: { route: AuthAppRoute }) {
 *   const getFullPath = useAuthShellFullPath()
 *   return <Link to={getFullPath(route.path)}>{route.label}</Link>
 * }
 * ```
 */
export function useAuthShellFullPath(): (path: string) => string {
  return useMemo(() => {
    return (path: string) => path
  }, [])
}
