'use client'

import { Component, type ReactNode } from 'react'

/** Known widget names with custom error messages */
type KnownWidgetName = 'profile' | 'security' | 'sessions' | 'api-keys' | 'team' | 'integrations'

interface WidgetErrorBoundaryProps {
  children: ReactNode
  /** Widget name for contextual error messages (known names get fun messages, others get a friendly default) */
  widgetName?: KnownWidgetName | (string & {})
  /** Custom fallback UI (overrides default error message) */
  fallback?: ReactNode
}

interface WidgetErrorBoundaryState {
  hasError: boolean
  error?: Error
}

/** Friendly, contextual error messages for known widget types */
const widgetErrorMessages: Record<KnownWidgetName, string> = {
  profile: "Your profile is camera shy right now...",
  security: "Security settings are being extra secure (maybe too secure)...",
  sessions: "Your sessions are having a session of their own...",
  'api-keys': "Your API keys are playing hide and seek...",
  team: "Your team members wandered off for a moment...",
  integrations: "Your integrations are having connection issues (ironic, we know)...",
}

/** Words that should be fully uppercased */
const uppercaseWords = new Set(['api', 'sso', 'mfa', 'oauth', 'jwt', 'url', 'id'])

/** Formats a widget name for display: "api-keys" -> "API Keys" */
function formatWidgetName(widgetName: string): string {
  return widgetName
    .split('-')
    .map(word => {
      const lower = word.toLowerCase()
      if (uppercaseWords.has(lower)) {
        return word.toUpperCase()
      }
      return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
    })
    .join(' ')
}

/** Generates a friendly error message - fun message for known widgets, friendly default for others */
function getErrorMessage(widgetName?: string): string {
  if (!widgetName) {
    return "Something went wrong loading this widget."
  }

  const knownMessage = widgetErrorMessages[widgetName as KnownWidgetName]
  if (knownMessage) {
    return knownMessage
  }

  // Friendly fallback: "Something went wrong loading your API Keys..."
  return `Something went wrong loading your ${formatWidgetName(widgetName)}...`
}

/**
 * Error boundary for WorkOS widgets.
 * Catches rendering errors and displays a friendly, contextual fallback UI.
 */
export class WidgetErrorBoundary extends Component<
  WidgetErrorBoundaryProps,
  WidgetErrorBoundaryState
> {
  constructor(props: WidgetErrorBoundaryProps) {
    super(props)
    this.state = { hasError: false }
  }

  static getDerivedStateFromError(error: Error): WidgetErrorBoundaryState {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error('[WidgetErrorBoundary] Widget error:', error, errorInfo)
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback
      }

      const message = getErrorMessage(this.props.widgetName)

      return (
        <div className="flex flex-col items-center justify-center gap-2 rounded-md border border-dashed py-12">
          <p className="text-muted-foreground text-sm">{message}</p>
          <p className="text-muted-foreground/60 text-xs">
            Try refreshing the page.
          </p>
        </div>
      )
    }

    return this.props.children
  }
}
