'use client'

import { useAuth } from '../../hooks/use-auth'
import { Pipes } from '../../widgets/pipes'
import { WidgetErrorBoundary } from '../components'

/**
 * Integrations page that renders the Pipes widget
 *
 * Allows users to connect and manage third-party integrations.
 */
export function IntegrationsPage() {
  const { user, getAccessToken, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Integrations</h1>
          <p className="text-muted-foreground">Connect and manage third-party services</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to manage your integrations.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">Integrations</h1>
        <p className="text-muted-foreground">Connect and manage third-party services</p>
      </div>
      <WidgetErrorBoundary widgetName="integrations">
        <Pipes authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
