'use client'

import { useAuth } from '../../hooks/use-auth'
import { UserProfile } from '../../widgets/user-profile'
import { WidgetErrorBoundary } from '../components'

/**
 * Profile page that renders the UserProfile widget
 *
 * Displays user account information including name, email, and profile picture.
 */
export function ProfilePage() {
  const { user, getAccessToken, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Profile</h1>
          <p className="text-muted-foreground">Manage your account information</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to view your profile.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">Profile</h1>
        <p className="text-muted-foreground">Manage your account information</p>
      </div>
      <WidgetErrorBoundary widgetName="profile">
        <UserProfile authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
