'use client'

/**
 * Breadcrumbs Component
 *
 * Router-agnostic breadcrumbs that can work with any Link component.
 * Defaults to @mdxui/navigation/web WebLink for TanStack Router.
 * Uses @mdxui/primitives breadcrumb components under the hood.
 */

import { WebLink } from '@mdxui/navigation/web'
import {
  Breadcrumb,
  BreadcrumbEllipsis,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '@mdxui/primitives/breadcrumb'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@mdxui/primitives/dropdown-menu'
import * as React from 'react'

/**
 * Props for the Link component
 */
export interface BreadcrumbLinkProps {
  href: string
  children: React.ReactNode
  className?: string
  onClick?: () => void
}

/**
 * Single breadcrumb item configuration
 */
export interface BreadcrumbItemConfig {
  /** Display label */
  label: string
  /** Route path - last item should not have href */
  href?: string
}

/**
 * Props for the Breadcrumbs component
 */
export interface BreadcrumbsProps {
  /** Array of breadcrumb items */
  items: BreadcrumbItemConfig[]
  /** Custom link component (e.g., Next.js Link, TanStack Link). Defaults to WebLink */
  LinkComponent?: React.ComponentType<BreadcrumbLinkProps>
  /** Additional class names */
  className?: string
  /** Maximum items to show before collapsing */
  maxItems?: number
  /** Custom separator element */
  separator?: React.ReactNode
}

/**
 * Default link component using @mdxui/navigation/web WebLink
 */
function DefaultLink({ href, children, className }: BreadcrumbLinkProps) {
  return (
    <WebLink to={href} className={className}>
      {children}
    </WebLink>
  )
}

/**
 * Breadcrumbs provides navigation context showing the user's location.
 *
 * Features:
 * - Router-agnostic - works with any Link component
 * - Defaults to @mdxui/navigation/web WebLink for TanStack Router
 * - Automatic collapse with dropdown for long paths
 * - Accessible breadcrumb semantics
 * - Custom separator support
 *
 * @example
 * ```tsx
 * // With default WebLink (TanStack Router)
 * <Breadcrumbs
 *   items={[
 *     { label: 'Home', href: '/' },
 *     { label: 'Users', href: '/users' },
 *     { label: 'John Doe' },
 *   ]}
 * />
 *
 * // With Next.js Link
 * import NextLink from 'next/link'
 *
 * <Breadcrumbs
 *   items={breadcrumbItems}
 *   LinkComponent={NextLink}
 * />
 *
 * // With custom Link wrapper
 * <Breadcrumbs
 *   items={breadcrumbItems}
 *   LinkComponent={({ href, children, className }) => (
 *     <MyCustomLink to={href} className={className}>{children}</MyCustomLink>
 *   )}
 * />
 * ```
 */
export function Breadcrumbs({
  items,
  LinkComponent = DefaultLink,
  className,
  maxItems = 4,
  separator,
}: BreadcrumbsProps) {
  // Handle empty items
  if (!items || items.length === 0) {
    return null
  }

  // Determine if we need to collapse items
  const shouldCollapse = items.length > maxItems
  const visibleItems = shouldCollapse
    ? [items[0], ...items.slice(-(maxItems - 1))]
    : items
  const hiddenItems = shouldCollapse
    ? items.slice(1, -(maxItems - 1))
    : []

  return (
    <Breadcrumb className={className}>
      <BreadcrumbList>
        {visibleItems.map((item, index) => {
          const isLast = index === visibleItems.length - 1
          const isFirst = index === 0

          // Insert ellipsis after first item if collapsing
          if (shouldCollapse && isFirst) {
            return (
              <React.Fragment key={item.label}>
                <BreadcrumbItem>
                  {item.href ? (
                    <BreadcrumbLink asChild>
                      <LinkComponent href={item.href}>{item.label}</LinkComponent>
                    </BreadcrumbLink>
                  ) : (
                    <BreadcrumbPage>{item.label}</BreadcrumbPage>
                  )}
                </BreadcrumbItem>
                <BreadcrumbSeparator>{separator}</BreadcrumbSeparator>
                <BreadcrumbItem>
                  <DropdownMenu>
                    <DropdownMenuTrigger
                      className="flex items-center gap-1 hover:text-foreground"
                      aria-label="Show hidden breadcrumbs"
                    >
                      <BreadcrumbEllipsis className="size-4" />
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start">
                      {hiddenItems.map((hiddenItem) => (
                        <DropdownMenuItem key={hiddenItem.label} asChild>
                          <LinkComponent href={hiddenItem.href || '#'}>
                            {hiddenItem.label}
                          </LinkComponent>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                </BreadcrumbItem>
                <BreadcrumbSeparator>{separator}</BreadcrumbSeparator>
              </React.Fragment>
            )
          }

          return (
            <React.Fragment key={item.label}>
              <BreadcrumbItem>
                {isLast ? (
                  <BreadcrumbPage>{item.label}</BreadcrumbPage>
                ) : item.href ? (
                  <BreadcrumbLink asChild>
                    <LinkComponent href={item.href}>{item.label}</LinkComponent>
                  </BreadcrumbLink>
                ) : (
                  <BreadcrumbPage>{item.label}</BreadcrumbPage>
                )}
              </BreadcrumbItem>
              {!isLast && <BreadcrumbSeparator>{separator}</BreadcrumbSeparator>}
            </React.Fragment>
          )
        })}
      </BreadcrumbList>
    </Breadcrumb>
  )
}

Breadcrumbs.displayName = 'Breadcrumbs'
