/**
 * Environment Variable Configuration
 *
 * Reads configuration from environment variables for zero-config setup.
 * Supports Vite's import.meta.env pattern for Cloudflare Workers Static Assets.
 *
 * Environment variables:
 * - VITE_WORKOS_CLIENT_ID - WorkOS client ID (required for zero-config)
 * - VITE_WORKOS_REDIRECT_URI - OAuth redirect URI
 * - VITE_WORKOS_API_HOSTNAME - WorkOS API hostname override
 * - VITE_WORKOS_DEV_MODE - Enable dev mode ("true" or "false")
 * - VITE_APP_NAME - Application name for branding
 * - VITE_APP_TAGLINE - Application tagline
 *
 * @example
 * ```bash
 * # .env file
 * VITE_WORKOS_CLIENT_ID=client_01JQYTRXK9ZPD8JPJTKDCRB656
 * VITE_WORKOS_REDIRECT_URI=https://oauth.do/callback
 * VITE_APP_NAME=OAuth.do
 * ```
 */

import type { AuthAppConfig } from './types'

/** Check if we're in a Vite environment */
function getEnvVar(key: string): string | undefined {
  // Vite injects import.meta.env at build time
  if (typeof import.meta !== 'undefined' && import.meta.env) {
    return import.meta.env[key] as string | undefined
  }
  // Fallback to process.env for Node.js environments
  if (typeof process !== 'undefined' && process.env) {
    return process.env[key]
  }
  return undefined
}

/**
 * Get configuration from environment variables
 *
 * Returns a partial config that can be merged with explicit config.
 * Missing required fields will cause runtime errors if not provided elsewhere.
 */
export function getEnvConfig(): Partial<AuthAppConfig> {
  const clientId = getEnvVar('VITE_WORKOS_CLIENT_ID')
  const redirectUri = getEnvVar('VITE_WORKOS_REDIRECT_URI')
  const apiHostname = getEnvVar('VITE_WORKOS_API_HOSTNAME')
  const devModeStr = getEnvVar('VITE_WORKOS_DEV_MODE')
  const appName = getEnvVar('VITE_APP_NAME')
  const appTagline = getEnvVar('VITE_APP_TAGLINE')

  // Only include identity if clientId is available
  const identity = clientId
    ? {
        clientId,
        ...(redirectUri && { redirectUri }),
        ...(apiHostname && { apiHostname }),
        ...(devModeStr && { devMode: devModeStr === 'true' }),
      }
    : undefined

  // Only include branding if appName is available
  const branding = appName
    ? {
        name: appName,
        ...(appTagline && { tagline: appTagline }),
      }
    : undefined

  return {
    ...(identity && { identity }),
    ...(branding && { branding }),
  }
}

/**
 * Merge explicit config with environment config
 *
 * Explicit config takes precedence over environment variables.
 */
export function mergeWithEnvConfig(config?: Partial<AuthAppConfig>): AuthAppConfig {
  const envConfig = getEnvConfig()

  // Deep merge branding
  const branding = {
    name: config?.branding?.name ?? envConfig.branding?.name ?? 'App',
    ...(config?.branding?.logo && { logo: config.branding.logo }),
    ...(config?.branding?.logoCollapsed && { logoCollapsed: config.branding.logoCollapsed }),
    tagline: config?.branding?.tagline ?? envConfig.branding?.tagline,
  }

  // Deep merge identity
  const envIdentity = envConfig.identity
  const configIdentity = config?.identity

  if (!envIdentity?.clientId && !configIdentity?.clientId) {
    throw new Error(
      'AuthApp: Missing clientId. Either provide config.identity.clientId or set VITE_WORKOS_CLIENT_ID environment variable.'
    )
  }

  const identity = {
    clientId: configIdentity?.clientId ?? envIdentity?.clientId ?? '',
    ...(configIdentity?.redirectUri ?? envIdentity?.redirectUri
      ? { redirectUri: configIdentity?.redirectUri ?? envIdentity?.redirectUri }
      : {}),
    ...(configIdentity?.apiHostname ?? envIdentity?.apiHostname
      ? { apiHostname: configIdentity?.apiHostname ?? envIdentity?.apiHostname }
      : {}),
    ...(configIdentity?.devMode ?? envIdentity?.devMode
      ? { devMode: configIdentity?.devMode ?? envIdentity?.devMode }
      : {}),
    ...(configIdentity?.required !== undefined ? { required: configIdentity.required } : {}),
    ...(configIdentity?.onUnauthenticated ? { onUnauthenticated: configIdentity.onUnauthenticated } : {}),
    ...(configIdentity?.landingComponent ? { landingComponent: configIdentity.landingComponent } : {}),
    ...(configIdentity?.loadingComponent ? { loadingComponent: configIdentity.loadingComponent } : {}),
    ...(configIdentity?.signOutRedirectUri ? { signOutRedirectUri: configIdentity.signOutRedirectUri } : {}),
    ...(configIdentity?.redirectUrl ? { redirectUrl: configIdentity.redirectUrl } : {}),
  }

  return {
    branding,
    identity,
    ...(config?.basePath && { basePath: config.basePath }),
    ...(config?.theme && { theme: config.theme }),
    ...(config?.auth && { auth: config.auth }),
    ...(config?.groups && { groups: config.groups }),
    ...(config?.routes && { routes: config.routes }),
  }
}
