import { StrictMode, useEffect, useState } from 'react'
import { createRoot } from 'react-dom/client'
import { AuthApp } from '../shell/auth-app'
import type { AuthAppConfig } from '../shell/types'
import { type AuthAppRuntimeConfig, ConfigError, loadConfig } from './config'
import { ProviderLandingPage } from './provider-landing'
import './tailwind.css'

function App() {
  const [config, setConfig] = useState<AuthAppRuntimeConfig | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    loadConfig()
      .then(setConfig)
      .catch((err) => {
        if (err instanceof ConfigError) {
          setError(err.message)
        } else {
          setError('An unexpected error occurred while loading configuration.')
        }
        console.error('Config load error:', err)
      })
  }, [])

  if (error) {
    return <ConfigErrorPage error={error} />
  }

  if (!config) {
    return <LoadingPage />
  }

  const authAppConfig: AuthAppConfig = {
    branding: {
      name: config.appName ?? 'App',
      tagline: config.tagline,
      logo: config.logoUrl ? (
        <img src={config.logoUrl} alt={config.appName ?? 'App'} className="h-6 w-6" />
      ) : undefined,
    },
    basePath: (config as any).basePath,
    identity: {
      clientId: config.clientId,
      redirectUri: config.redirectUri,
      apiHostname: config.apiHostname,
      devMode: config.devMode,
      onUnauthenticated: config.onUnauthenticated ?? (config.providers?.length ? 'landing' : undefined),
      redirectUrl: (config as any).redirectUrl || config.loginUrl,
      signOutRedirectUri: (config as any).signOutRedirectUri || config.loginUrl,
      landingComponent: config.providers?.length ? <ProviderLandingPage config={config} /> : undefined,
    },
  }

  return <AuthApp config={authAppConfig} />
}

function LoadingPage() {
  return (
    <div className="auth-app-loading">
      <div className="auth-app-loading-content">
        <div className="auth-app-loading-spinner" />
        <p className="auth-app-loading-text">Loading...</p>
      </div>
    </div>
  )
}

function ConfigErrorPage({ error }: { error: string }) {
  return (
    <div className="auth-app-error">
      <div className="auth-app-error-content">
        <div className="auth-app-error-icon">
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="48"
            height="48"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
            aria-hidden="true"
          >
            <circle cx="12" cy="12" r="10" />
            <line x1="12" y1="8" x2="12" y2="12" />
            <line x1="12" y1="16" x2="12.01" y2="16" />
          </svg>
        </div>
        <h1 className="auth-app-error-title">Configuration Required</h1>
        <p className="auth-app-error-message">{error}</p>
        <div className="auth-app-error-help">
          <p>Create an <code>auth-config.json</code> file with:</p>
          <pre className="auth-app-error-code">
            {JSON.stringify(
              {
                clientId: 'your_workos_client_id',
                appName: 'Your App Name',
              },
              null,
              2
            )}
          </pre>
        </div>
      </div>
    </div>
  )
}

const root = document.getElementById('root')
if (root) {
  createRoot(root).render(
    <StrictMode>
      <App />
    </StrictMode>
  )
}
