'use client'

import { useAuth } from '../../hooks/use-auth'
import { UsersManagement } from '../../widgets/users-management'
import { WidgetErrorBoundary } from '../components'

/**
 * Team page that renders the UsersManagement widget
 *
 * Requires organization membership and admin permissions to view.
 */
export function TeamPage() {
  const { user, getAccessToken, isLoading, organizationId, permissions } = useAuth()

  const hasOrganization = !!organizationId
  const canManageTeam = hasOrganization && permissions?.includes('widgets:users-table:manage')

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Team</h1>
          <p className="text-muted-foreground">Manage your team members and invitations</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to manage your team.
          </p>
        </div>
      </div>
    )
  }

  if (!hasOrganization) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Team</h1>
          <p className="text-muted-foreground">Manage your team members and invitations</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            You need to be part of an organization to manage team members.
          </p>
        </div>
      </div>
    )
  }

  if (!canManageTeam) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Team</h1>
          <p className="text-muted-foreground">Manage your team members and invitations</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            You need admin permissions to manage team members.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">Team</h1>
        <p className="text-muted-foreground">Manage your team members and invitations</p>
      </div>
      <WidgetErrorBoundary widgetName="team">
        <UsersManagement authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
