'use client'

import { useEffect, useRef } from 'react'
import { useAuth } from '@id.org.ai/react'
import type { AuthGateProps } from '../types/auth'

/**
 * Default loading component shown while checking authentication
 */
function DefaultLoadingComponent() {
  return (
    <div className="min-h-screen bg-background flex items-center justify-center">
      <div className="flex flex-col items-center gap-4">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
        <p className="text-sm text-muted-foreground">Loading...</p>
      </div>
    </div>
  )
}

/**
 * Default landing page component shown when user is not authenticated
 */
function DefaultLandingPage() {
  const { signIn } = useAuth()

  return (
    <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
      <div className="text-center max-w-md">
        <h1 className="text-3xl font-bold tracking-tight mb-4">Welcome</h1>
        <p className="text-muted-foreground mb-8">
          Sign in to access your dashboard.
        </p>
        <button
          type="button"
          onClick={() => signIn({ state: { returnTo: typeof window !== 'undefined' ? window.location.pathname + window.location.search : '/' } })}
          className="inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-[var(--radius-md)] text-sm font-medium transition-colors bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-6"
        >
          Sign In
        </button>
      </div>
    </div>
  )
}

/**
 * AuthGate handles authentication state and shows appropriate UI:
 * - Loading state while checking auth
 * - Landing page or redirect when not authenticated
 * - Children (protected content) when authenticated
 *
 * @example
 * ```tsx
 * import { AuthGate } from '@mdxui/auth'
 *
 * function App() {
 *   return (
 *     <AuthGate>
 *       <ProtectedDashboard />
 *     </AuthGate>
 *   )
 * }
 * ```
 *
 * @example
 * ```tsx
 * // With custom components
 * <AuthGate
 *   loadingComponent={<CustomSpinner />}
 *   landingComponent={<CustomLandingPage />}
 * >
 *   <Dashboard />
 * </AuthGate>
 * ```
 *
 * @example
 * ```tsx
 * // Allow unauthenticated access
 * <AuthGate required={false}>
 *   <PublicContent />
 * </AuthGate>
 * ```
 *
 * @example
 * ```tsx
 * // Redirect to external URL when not authenticated
 * <AuthGate
 *   onUnauthenticated="redirect"
 *   redirectUrl="https://marketing.example.com"
 * >
 *   <Dashboard />
 * </AuthGate>
 * ```
 */
export function AuthGate({
  children,
  required = true,
  loadingComponent,
  landingComponent,
  onUnauthenticated = 'landing',
  redirectUrl,
}: AuthGateProps) {
  const { user, isLoading, signIn } = useAuth()
  const signInCalled = useRef(false)

  // Auto sign-in effect for 'signIn' mode
  useEffect(() => {
    if (onUnauthenticated === 'signIn' && !isLoading && !user && !signInCalled.current) {
      signInCalled.current = true
      signIn({ state: { returnTo: typeof window !== 'undefined' ? window.location.pathname + window.location.search : '/' } })
    }
  }, [onUnauthenticated, isLoading, user, signIn])

  // Reset flag when user logs in
  useEffect(() => {
    if (user) {
      signInCalled.current = false
    }
  }, [user])

  // If auth is not required, always show children
  if (!required) {
    return <>{children}</>
  }

  // Show loading state while checking authentication
  if (isLoading) {
    return <>{loadingComponent ?? <DefaultLoadingComponent />}</>
  }

  // User is authenticated, show protected content
  if (user) {
    return <>{children}</>
  }

  // User is not authenticated - handle based on config
  switch (onUnauthenticated) {
    case 'signIn':
      // Auto sign-in mode - show loading while redirecting to auth
      return <>{loadingComponent ?? <DefaultLoadingComponent />}</>

    case 'redirect':
      // Redirect to external URL
      if (redirectUrl && typeof window !== 'undefined') {
        window.location.href = redirectUrl
        return (
          <div className="min-h-screen bg-background flex items-center justify-center">
            <p className="text-sm text-muted-foreground">Redirecting...</p>
          </div>
        )
      }
      // Fall through to landing if no redirect URL
      return <>{landingComponent ?? <DefaultLandingPage />}</>

    case 'allow':
      // Allow access even without auth (shows children)
      return <>{children}</>

    case 'landing':
      // Show landing page (custom or default)
      return <>{landingComponent ?? <DefaultLandingPage />}</>
  }
}
