'use client'

/**
 * AuthShellNav Component
 *
 * Sidebar navigation component that renders routes organized by group.
 * Includes branding header and user menu footer.
 *
 * Routes are automatically filtered based on user context:
 * - Routes with `requiresOrganization: true` are hidden when user has no org
 * - Routes with `requiredPermissions` are hidden when user lacks permissions
 * - Routes with `requiredRoles` are hidden when user lacks roles
 */

import { useMemo, type ReactNode } from 'react'
import { useAuth } from '@id.org.ai/react'
import { useIsActive, WebLink } from '@mdxui/navigation/web'
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarRail,
} from '@mdxui/primitives/sidebar'
import { SidebarUser } from '@mdxui/primitives/sidebar-user'

import { useAuthShellBranding, useAuthShellRoutesByGroup, useAuthShellFullPath, useAuthShellConfig } from './config-context'
import type { AuthShellNavProps, AuthAppRoute } from './types'

/**
 * Check if a route should be visible based on user context
 */
function isRouteVisible(
  route: AuthAppRoute,
  context: {
    organizationId?: string
    permissions?: string[]
    role?: string
  }
): boolean {
  const { organizationId, permissions = [], role } = context

  // Check organization requirement
  if (route.requiresOrganization && !organizationId) {
    return false
  }

  // Check required permissions (user must have ALL)
  if (route.requiredPermissions && route.requiredPermissions.length > 0) {
    const hasAllPermissions = route.requiredPermissions.every((p) =>
      permissions.includes(p)
    )
    if (!hasAllPermissions) {
      return false
    }
  }

  // Check required roles (user must have at least ONE)
  if (route.requiredRoles && route.requiredRoles.length > 0) {
    const hasRole = role && route.requiredRoles.includes(role)
    if (!hasRole) {
      return false
    }
  }

  return true
}

/**
 * Navigation item component
 */
function NavItem({ route, getFullPath }: { route: AuthAppRoute; getFullPath: (path: string) => string }) {
  const fullPath = getFullPath(route.path)
  // For root path use exact match, for others use partial match
  const isActive = useIsActive(fullPath, { partial: fullPath !== '/' })
  const Icon = route.icon

  return (
    <SidebarMenuItem>
      <SidebarMenuButton asChild isActive={isActive} tooltip={route.label}>
        <WebLink to={fullPath}>
          {Icon && <Icon className="size-4" />}
          <span>{route.label}</span>
        </WebLink>
      </SidebarMenuButton>
    </SidebarMenuItem>
  )
}

/**
 * Default branding header component
 */
function BrandingHeader({ headerContent }: { headerContent?: ReactNode }) {
  const branding = useAuthShellBranding()

  if (headerContent) {
    return <>{headerContent}</>
  }

  return (
    <div className="flex items-center gap-2 px-2">
      {branding.logo && <div className="flex-shrink-0">{branding.logo}</div>}
      <div className="flex flex-col gap-0.5 leading-none">
        <span className="font-semibold">{branding.name}</span>
        {branding.tagline && (
          <span className="text-xs text-muted-foreground">{branding.tagline}</span>
        )}
      </div>
    </div>
  )
}

/**
 * Default user menu component
 */
function DefaultUserMenu() {
  const { user, signOut } = useAuth()
  const { config } = useAuthShellConfig()

  if (!user) return null

  const displayName = user.firstName
    ? `${user.firstName}${user.lastName ? ` ${user.lastName}` : ''}`
    : user.email ?? 'User'

  return (
    <SidebarUser
      user={{
        name: displayName,
        email: user.email ?? '',
        avatar: user.profilePictureUrl ?? undefined,
      }}
      onSignOut={() => signOut({ redirectTo: config.identity.signOutRedirectUri })}
    />
  )
}

/**
 * AuthShellNav - Sidebar navigation component
 *
 * Renders navigation routes organized by group with branding
 * header and user menu footer.
 *
 * @example
 * ```tsx
 * <AuthShellNav
 *   headerContent={<TeamSwitcher />}
 *   userMenu={<CustomUserMenu />}
 * />
 * ```
 */
export function AuthShellNav({ headerContent, userMenu, className }: AuthShellNavProps) {
  const { routesByGroup, groups } = useAuthShellRoutesByGroup()
  const getFullPath = useAuthShellFullPath()
  const { user, organizationId, permissions } = useAuth()
  const role = user?.role ?? null

  // Filter routes based on user context (org, permissions, roles)
  const filteredRoutesByGroup = useMemo(() => {
    const context = {
      organizationId: organizationId ?? undefined,
      permissions: permissions ?? undefined,
      role: role ?? undefined,
    }
    const filtered = new Map<string, AuthAppRoute[]>()

    for (const [groupId, routes] of routesByGroup) {
      const visibleRoutes = routes.filter((route) => isRouteVisible(route, context))
      if (visibleRoutes.length > 0) {
        filtered.set(groupId, visibleRoutes)
      }
    }

    return filtered
  }, [routesByGroup, organizationId, permissions, role])

  return (
    <Sidebar collapsible="icon" className={className}>
      <SidebarHeader>
        <BrandingHeader headerContent={headerContent} />
      </SidebarHeader>
      <SidebarContent>
        {groups.map((group) => {
          const routes = filteredRoutesByGroup.get(group.id)
          if (!routes || routes.length === 0) return null

          return (
            <SidebarGroup key={group.id}>
              {group.label && <SidebarGroupLabel>{group.label}</SidebarGroupLabel>}
              <SidebarGroupContent>
                <SidebarMenu>
                  {routes.map((route) => (
                    <NavItem key={route.key} route={route} getFullPath={getFullPath} />
                  ))}
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>
          )
        })}
      </SidebarContent>
      <SidebarFooter>
        {userMenu ?? <DefaultUserMenu />}
      </SidebarFooter>
      <SidebarRail />
    </Sidebar>
  )
}
