'use client'

import { useAuth } from '../../hooks/use-auth'
import { UserSessions } from '../../widgets/user-sessions'
import { WidgetErrorBoundary } from '../components'

/**
 * Sessions page that renders the UserSessions widget
 *
 * Displays active sessions and allows users to revoke them.
 */
export function SessionsPage() {
  const { user, getAccessToken, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">Sessions</h1>
          <p className="text-muted-foreground">View and manage your active sessions</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to view your sessions.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">Sessions</h1>
        <p className="text-muted-foreground">View and manage your active sessions</p>
      </div>
      <WidgetErrorBoundary widgetName="sessions">
        <UserSessions authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
