'use client'

import { useAuth } from '../../hooks/use-auth'
import { ApiKeys } from '../../widgets/api-keys'
import { WidgetErrorBoundary } from '../components'

/**
 * API Keys page that renders the ApiKeys widget
 *
 * Allows users to create and manage their API keys.
 */
export function ApiKeysPage() {
  const { user, getAccessToken, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12 text-muted-foreground">
        Loading...
      </div>
    )
  }

  if (!user) {
    return (
      <div className="container max-w-4xl py-8">
        <div className="mb-8">
          <h1 className="text-2xl font-semibold tracking-tight">API Keys</h1>
          <p className="text-muted-foreground">Create and manage your API keys</p>
        </div>
        <div className="flex items-center justify-center rounded-md border border-dashed py-24">
          <p className="text-muted-foreground text-sm">
            Please sign in to manage your API keys.
          </p>
        </div>
      </div>
    )
  }

  return (
    <div className="container max-w-4xl py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold tracking-tight">API Keys</h1>
        <p className="text-muted-foreground">Create and manage your API keys</p>
      </div>
      <WidgetErrorBoundary widgetName="api-keys">
        <ApiKeys authToken={getAccessToken} />
      </WidgetErrorBoundary>
    </div>
  )
}
