'use client'

import { useAuth, useOrganizations } from '@id.org.ai/react'
import { Button } from '@mdxui/primitives/button'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@mdxui/primitives/dialog'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@mdxui/primitives/dropdown-menu'
import { Input } from '@mdxui/primitives/input'
import { SidebarMenu, SidebarMenuButton, SidebarMenuItem } from '@mdxui/primitives/sidebar'
import { Building2, Check, ChevronsUpDown, Plus } from 'lucide-react'
import type { ReactNode } from 'react'
import { useState } from 'react'

export interface TeamSwitcherProps {
  renderWrapper?: (children: ReactNode) => ReactNode
  renderNoOrganization?: () => ReactNode
  className?: string
}

export function TeamSwitcher({
  renderNoOrganization,
  className,
}: TeamSwitcherProps) {
  const { organizationId } = useAuth()
  const { organizations, switchOrganization, createOrganization, isCreating, isLoading } = useOrganizations()
  const [dialogOpen, setDialogOpen] = useState(false)
  const [newOrgName, setNewOrgName] = useState('')

  const activeOrg = organizations.find((o) => o.id === organizationId)

  if (isLoading) {
    return (
      <SidebarMenu>
        <SidebarMenuItem>
          <SidebarMenuButton className="pointer-events-none">
            <Building2 />
            <span className="truncate group-data-[collapsible=icon]:hidden">Loading...</span>
          </SidebarMenuButton>
        </SidebarMenuItem>
      </SidebarMenu>
    )
  }

  if (!organizations.length && !organizationId) {
    return renderNoOrganization?.() ?? (
      <SidebarMenu>
        <SidebarMenuItem>
          <SidebarMenuButton className="pointer-events-none">
            <Building2 />
            <span className="truncate group-data-[collapsible=icon]:hidden">No Organization</span>
          </SidebarMenuButton>
        </SidebarMenuItem>
      </SidebarMenu>
    )
  }

  async function handleSwitch(orgId: string) {
    if (orgId === organizationId) return
    await switchOrganization(orgId)
  }

  async function handleCreate() {
    const name = newOrgName.trim()
    if (!name) return
    try {
      await createOrganization(name)
      setDialogOpen(false)
      setNewOrgName('')
    } catch {
      // Error handled by mutation state
    }
  }

  return (
    <>
      <SidebarMenu>
        <SidebarMenuItem>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <SidebarMenuButton
                tooltip={activeOrg?.name ?? 'Organization'}
                className={`w-full justify-between ${className ?? ''}`}
              >
                <span className="flex items-center gap-2 truncate">
                  <Building2 className="size-4 shrink-0" />
                  <span className="truncate group-data-[collapsible=icon]:hidden">
                    {activeOrg?.name ?? 'Select Organization'}
                  </span>
                </span>
                <ChevronsUpDown className="size-4 shrink-0 opacity-50 group-data-[collapsible=icon]:hidden" />
              </SidebarMenuButton>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="start" className="min-w-[var(--radix-popper-anchor-width)] font-normal">
              <DropdownMenuLabel className="text-sm font-normal text-muted-foreground">Organizations</DropdownMenuLabel>
              <DropdownMenuGroup className="!font-normal">
                {organizations.map((org) => {
                  const isActive = org.id === organizationId
                  return (
                    <DropdownMenuItem
                      key={org.id}
                      onSelect={() => handleSwitch(org.id)}
                      className={isActive ? 'bg-sidebar-accent text-sidebar-accent-foreground' : ''}
                    >
                      <span className="flex-1 truncate">{org.name}</span>
                      {isActive && <Check className="size-4 shrink-0 !text-sidebar-accent-foreground" />}
                    </DropdownMenuItem>
                  )
                })}
              </DropdownMenuGroup>
              <DropdownMenuSeparator />
              <DropdownMenuItem onSelect={() => setDialogOpen(true)} className="text-sm font-normal">
                <Plus className="mr-2 size-4" />
                Create Organization
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </SidebarMenuItem>
      </SidebarMenu>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create Organization</DialogTitle>
            <DialogDescription>Create a new team organization to collaborate with others.</DialogDescription>
          </DialogHeader>
          <form
            onSubmit={(e) => {
              e.preventDefault()
              handleCreate()
            }}
          >
            <Input
              placeholder="Organization name"
              value={newOrgName}
              onChange={(e) => setNewOrgName(e.target.value)}
              autoFocus
            />
            <DialogFooter className="mt-4">
              <Button type="button" variant="outline" onClick={() => setDialogOpen(false)}>
                Cancel
              </Button>
              <Button type="submit" disabled={!newOrgName.trim() || isCreating}>
                {isCreating ? 'Creating...' : 'Create'}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </>
  )
}
