'use client'

/**
 * AuthApp Component
 *
 * Complete application wrapper that sets up all required providers,
 * shell structure, and routing for an authenticated application.
 *
 * Now includes built-in routing via @mdxui/navigation - just define
 * routes in your config and AuthApp handles the rest.
 */

import type { RouteConfig } from '@mdxui/navigation'
import { createWebRouter, RouterProvider, WebOutlet } from '@mdxui/navigation/web'
import { ThemeProvider } from 'next-themes'
import React, { type ReactNode, useMemo } from 'react'
import { IdentityProvider } from '../providers/identity-provider'
import { AuthShell } from './auth-shell'
import { SidebarOrgSwitcher } from './components'
import { AuthShellConfigProvider } from './config-context'
import { mergeWithEnvConfig } from './env-config'
import { defaultGroups, defaultRoutes } from './route-presets'
import type { AuthAppConfig, AuthAppProps, AuthAppRoute } from './types'

/**
 * Props for AuthAppProvider (providers only, no shell or routing)
 */
interface AuthAppProviderProps {
  /**
   * Application configuration
   *
   * Optional when VITE_WORKOS_CLIENT_ID environment variable is set.
   */
  config?: Partial<AuthAppConfig>
  /** Children to render */
  children: ReactNode
}

/**
 * AuthAppProvider - Providers only wrapper
 *
 * Use this when you need to customize the shell layout or
 * integrate with an existing routing setup.
 *
 * Provider hierarchy:
 * - ThemeProvider (next-themes)
 * - AuthShellConfigProvider
 * - IdentityProvider (WorkOS AuthKit)
 *
 * @example
 * ```tsx
 * <AuthAppProvider config={config}>
 *   <RouterProvider router={router}>
 *     <AuthShell>
 *       <Outlet />
 *     </AuthShell>
 *   </RouterProvider>
 * </AuthAppProvider>
 * ```
 *
 * @example
 * ```tsx
 * // Zero-config with environment variables
 * <AuthAppProvider>
 *   <MyApp />
 * </AuthAppProvider>
 * ```
 */
export function AuthAppProvider({ config, children }: AuthAppProviderProps) {
  // Merge explicit config with environment variables
  const resolvedConfig = useMemo(() => mergeWithEnvConfig(config), [config])
  const { identity, theme } = resolvedConfig

  return (
    <ThemeProvider
      attribute="class"
      defaultTheme={theme?.mode ?? 'system'}
      enableSystem
      disableTransitionOnChange
    >
      <AuthShellConfigProvider config={resolvedConfig}>
        <IdentityProvider
          clientId={identity.clientId}
          apiHostname={identity.apiHostname}
          devMode={identity.devMode}
          redirectUri={identity.redirectUri}
        >
          {children}
        </IdentityProvider>
      </AuthShellConfigProvider>
    </ThemeProvider>
  )
}

/**
 * Convert AuthAppRoute[] to RouteConfig for @mdxui/navigation
 */
function convertRoutesToConfig(routes: AuthAppRoute[], basePath?: string): RouteConfig {
  const config: RouteConfig = {}
  let firstRoutePath: string | undefined

  for (const route of routes) {
    if (route.enabled === false) continue

    const fullPath = basePath ? `${basePath}${route.path}` : route.path
    if (!firstRoutePath) firstRoutePath = fullPath

    config[route.key] = {
      path: fullPath,
      component: route.component as React.ComponentType<unknown>,
      meta: {
        label: route.label,
        icon: route.icon,
        group: route.group,
        public: route.public,
        requiredRoles: route.requiredRoles,
        requiredPermissions: route.requiredPermissions,
      },
    }
  }

  // Add index route that redirects to the first route when basepath is loaded directly
  if (firstRoutePath) {
    config['__index'] = {
      index: true,
      redirect: firstRoutePath,
    }
  }

  return config
}

/**
 * Root layout component that wraps all routes with AuthShell
 */
function createRootLayout(headerContent?: ReactNode, sidebarHeaderContent?: ReactNode) {
  // Default to SidebarOrgSwitcher if no custom header content provided
  const resolvedSidebarContent = sidebarHeaderContent ?? <SidebarOrgSwitcher />

  return function RootLayout() {
    return (
      <AuthShell headerContent={headerContent} sidebarHeaderContent={resolvedSidebarContent}>
        <WebOutlet />
      </AuthShell>
    )
  }
}

/**
 * AuthApp - Complete app with built-in routing
 *
 * This is the recommended way to use AuthApp. Define your routes
 * in the config and AuthApp handles routing automatically.
 *
 * @example
 * ```tsx
 * // Zero-config with environment variables
 * // Set VITE_WORKOS_CLIENT_ID, VITE_APP_NAME in .env
 * function App() {
 *   return <AuthApp />
 * }
 * ```
 *
 * @example
 * ```tsx
 * import { AuthApp, type AuthAppConfig } from '@mdxui/auth/shell'
 * import { Home, Settings, Users } from 'lucide-react'
 *
 * const config: AuthAppConfig = {
 *   branding: { name: 'My App' },
 *   identity: { clientId: 'client_xxx' },
 *   routes: [
 *     { key: 'home', label: 'Home', path: '/', icon: Home, component: HomePage },
 *     { key: 'settings', label: 'Settings', path: '/settings', icon: Settings, component: SettingsPage },
 *     { key: 'users', label: 'Users', path: '/users', icon: Users, component: UsersPage },
 *   ],
 * }
 *
 * function App() {
 *   return <AuthApp config={config} />
 * }
 * ```
 *
 * @example
 * ```tsx
 * // With custom header content (sidebar defaults to SidebarOrgSwitcher)
 * <AuthApp
 *   config={config}
 *   headerContent={<ThemeSwitcher />}
 * />
 * ```
 *
 * @example
 * ```tsx
 * // Override sidebar header with custom content
 * <AuthApp
 *   config={config}
 *   sidebarHeaderContent={<MyCustomSwitcher />}
 * />
 * ```
 */
export function AuthApp({ config, headerContent, sidebarHeaderContent }: AuthAppProps) {
  // Merge with env config first
  const mergedConfig = useMemo(() => mergeWithEnvConfig(config), [config])

  // Resolve routes and groups with defaults
  const routes = mergedConfig.routes ?? defaultRoutes
  const groups = mergedConfig.groups ?? defaultGroups
  const resolvedConfig = useMemo(
    () => ({ ...mergedConfig, routes, groups }),
    [mergedConfig, routes, groups]
  )

  // Convert routes and create router - memoized to prevent recreation
  const router = useMemo(() => {
    const routeConfig = convertRoutesToConfig(routes)
    const RootLayout = createRootLayout(headerContent, sidebarHeaderContent)

    return createWebRouter(routeConfig, {
      rootComponent: RootLayout,
      basepath: mergedConfig.basePath || undefined,
    })
  }, [routes, mergedConfig.basePath, headerContent, sidebarHeaderContent])

  return (
    <AuthAppProvider config={resolvedConfig}>
      <RouterProvider router={router} />
    </AuthAppProvider>
  )
}

/**
 * AuthAppWithChildren - App wrapper with shell but no routing
 *
 * Use this when you want the shell but handle routing yourself,
 * or when you have simple static content.
 *
 * @example
 * ```tsx
 * // Zero-config with environment variables
 * <AuthAppWithChildren>
 *   <Dashboard />
 * </AuthAppWithChildren>
 * ```
 *
 * @example
 * ```tsx
 * // With your own router
 * <AuthAppWithChildren config={config}>
 *   <Routes>
 *     <Route path="/" element={<Home />} />
 *     <Route path="/settings" element={<Settings />} />
 *   </Routes>
 * </AuthAppWithChildren>
 * ```
 *
 * @example
 * ```tsx
 * // With static content
 * <AuthAppWithChildren config={config}>
 *   <Dashboard />
 * </AuthAppWithChildren>
 * ```
 */
export function AuthAppWithChildren({
  config,
  headerContent,
  sidebarHeaderContent,
  children,
}: AuthAppProps & { children: ReactNode }) {
  // Merge with env config first
  const mergedConfig = useMemo(() => mergeWithEnvConfig(config), [config])

  // Resolve routes and groups with defaults
  const routes = mergedConfig.routes ?? defaultRoutes
  const groups = mergedConfig.groups ?? defaultGroups
  const resolvedConfig = useMemo(
    () => ({ ...mergedConfig, routes, groups }),
    [mergedConfig, routes, groups]
  )

  // Default to SidebarOrgSwitcher if no custom header content provided
  const resolvedSidebarContent = sidebarHeaderContent ?? <SidebarOrgSwitcher />

  return (
    <AuthAppProvider config={resolvedConfig}>
      <AuthShell headerContent={headerContent} sidebarHeaderContent={resolvedSidebarContent}>
        {children}
      </AuthShell>
    </AuthAppProvider>
  )
}

/**
 * Create route definitions from config for use with routers
 *
 * Helper function to generate route objects compatible with
 * React Router, TanStack Router, etc.
 *
 * @example
 * ```tsx
 * // React Router
 * const routes = createRouteDefinitions(config)
 * const router = createBrowserRouter(
 *   routes.map(r => ({ path: r.path, element: <r.component /> }))
 * )
 * ```
 *
 * @example
 * ```tsx
 * // TanStack Router
 * const routes = createRouteDefinitions(config)
 * const routeTree = rootRoute.addChildren(
 *   routes.map(r => createRoute({
 *     getParentRoute: () => rootRoute,
 *     path: r.path,
 *     component: r.component,
 *   }))
 * )
 * ```
 */
export function createRouteDefinitions(config?: Partial<AuthAppConfig>) {
  const mergedConfig = mergeWithEnvConfig(config)
  const basePath = mergedConfig.basePath ?? ''
  const routes = mergedConfig.routes ?? defaultRoutes

  return routes
    .filter((route) => route.enabled !== false)
    .map((route) => ({
      key: route.key,
      path: basePath ? `${basePath}${route.path}` : route.path,
      label: route.label,
      component: route.component,
      icon: route.icon,
      group: route.group,
      public: route.public,
      requiredRoles: route.requiredRoles,
      requiredPermissions: route.requiredPermissions,
    }))
}
