import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Type to omit React event handlers that conflict with Motion's event handlers.
 * Motion uses different signatures for onDrag, onAnimationStart, onAnimationEnd, etc.
 */
export type MotionSafeProps<T> = Omit<
  T,
  | "onDrag"
  | "onDragStart"
  | "onDragEnd"
  | "onAnimationStart"
  | "onAnimationEnd"
  | "onAnimationIteration"
>;
