'use client'

/**
 * AuthShell Component
 *
 * Main layout wrapper for authenticated applications.
 * Provides sidebar, header, and main content area with
 * authentication gating.
 */

import { Separator } from '@mdxui/primitives/separator'
import {
  SidebarInset,
  SidebarProvider,
  SidebarTrigger,
} from '@mdxui/primitives/sidebar'
import { Toaster } from '@mdxui/primitives/sonner'
import type { ReactNode } from 'react'

import { AuthGate } from '../providers/auth-gate'
import { AuthShellNav } from './auth-shell-nav'
import { type BreadcrumbItemConfig, Breadcrumbs } from './components'
import { useAuthShellConfig } from './config-context'
import type { AuthShellProps } from './types'

/**
 * Default header component with sidebar trigger and breadcrumbs
 */
function DefaultHeader({
  breadcrumbs,
  headerContent,
}: {
  breadcrumbs?: BreadcrumbItemConfig[]
  headerContent?: ReactNode
}) {
  return (
    <header className="relative flex h-12 shrink-0 items-center gap-2 border-b bg-background transition-[width,height] ease-linear group-has-data-[collapsible=icon]/sidebar-wrapper:h-12">
      <div className="z-10 flex shrink-0 items-center gap-2 bg-background px-4">
        <SidebarTrigger className="-ml-1" />
        <Separator orientation="vertical" className="mr-2 h-4" />
        {breadcrumbs && breadcrumbs.length > 0 && (
          <Breadcrumbs items={breadcrumbs} />
        )}
      </div>
      {headerContent && (
        <div className="flex flex-1 items-center px-4 xl:absolute xl:inset-0 xl:justify-center">
          <div className="w-full max-w-md">{headerContent}</div>
        </div>
      )}
    </header>
  )
}

/**
 * AuthShell - Main application shell layout
 *
 * Wraps content in authentication gate and provides
 * sidebar navigation with header and main content area.
 *
 * @example
 * ```tsx
 * <AuthShellConfigProvider config={config}>
 *   <IdentityProvider clientId={config.identity.clientId}>
 *     <AuthShell breadcrumbs={[{ label: 'Dashboard' }]}>
 *       <Outlet />
 *     </AuthShell>
 *   </IdentityProvider>
 * </AuthShellConfigProvider>
 * ```
 */
export function AuthShell({
  children,
  sidebarHeaderContent,
  headerContent,
  breadcrumbs,
}: AuthShellProps) {
  const { config } = useAuthShellConfig()
  const { identity, auth } = config

  return (
    <AuthGate
      required={identity.required ?? auth?.requireAuth ?? true}
      onUnauthenticated={identity.onUnauthenticated ?? auth?.onUnauthenticated ?? 'landing'}
      redirectUrl={identity.redirectUrl}
      loadingComponent={identity.loadingComponent}
      landingComponent={identity.landingComponent}
    >
      <SidebarProvider>
        <AuthShellNav headerContent={sidebarHeaderContent} />
        <SidebarInset>
          <DefaultHeader breadcrumbs={breadcrumbs} headerContent={headerContent} />
          <main className="flex-1 overflow-auto p-4">
            {children}
          </main>
        </SidebarInset>
      </SidebarProvider>
      <Toaster />
    </AuthGate>
  )
}
